//分块算法，复杂度:O(m*sqrt(n))
#include <bits/stdc++.h>
using namespace std;

typedef long long ll;

const int N=2e5+5,M=450;

int n,m,len;
ll a[N],sum[N],add[N],L[N],R[N];//64位整数

int Get(int x){
    //求x所在段的编号
    return (x-1)/len+1;
}

void modify(int l,int r,ll k){
    //将区间[l,r]中的所有数加上k
    int p=Get(l),q=Get(r);//得到l,r所在段
    if(p==q){
        //同段直接暴力
        for(int i=l;i<=r;i++)
            a[i]+=k,sum[p]+=k;
    }else{
        int i=l;
        for(;Get(i)==p;i++)
            a[i]+=k,sum[p]+=k;
        //第一个不完整部分（或完整部分）直接暴力
        i=r;
        for(;Get(i)==q;i--)
            a[i]+=k,sum[q]+=k;
        //最后一个不完整部分（或完整部分）直接暴力
        for(i=p+1;i<q;i++)
            add[i]+=k,sum[i]+=len*k;
        //剩下的完整部分打懒标记
    }
    //两端部分修改最坏O(2*sqrt(n))，中间完整部分修改最坏O(sqrt(n))，复杂度为O(sqrt(n))
}

ll query(int l,int r){
    //查询区间[l,r]的所有数之和
    int p=Get(l),q=Get(r);
    ll res=0;
    if(p==q){
        //同段直接暴力
        for(int i=l;i<=r;i++)
            res+=a[i];
        res+=add[p]*(r-l+1);//不要忘了懒标记
        return res;
    }else{
        int i=l;
        for(;Get(i)==p;i++)
            res+=a[i];
        res+=add[p]*(R[p]-l+1);
        i=r;
        for(;Get(i)==q;i--)
            res+=a[i];
        res+=add[q]*(r-L[q]+1);
        for(int i=p+1;i<q;i++)
            res+=sum[i];
        return res;
    }
}

int main(){
    scanf("%d%d",&n,&m);
    len=sqrt(n);//将n分成sqrt(n)段
    for(int i=1;i<=n;i++){
        scanf("%lld",&a[i]);
        sum[Get(i)]+=a[i];
    }
    for(int i=1;i*len<=n;i++)
        L[i]=R[i-1]+1,R[i]=i*len;
    if(n%len)
        L[n/len+1]=R[n/len]+1,R[n/len+1]=n;
    while(m--){
        int tp;
        scanf("%d",&tp);
        if(tp==1){
            int l,r;
            ll k;
            scanf("%d%d%lld",&l,&r,&k);
            modify(l,r,k);
        }else if(tp==2){
            ll k;
            scanf("%lld",&k);
            modify(1,1,k);
        }else if(tp==3){
            ll k;
            scanf("%lld",&k);
            modify(1,1,-k);
        }else if(tp==4){
            int l,r;
            scanf("%d%d",&l,&r);
            printf("%lld\n",query(l,r));
        }else if(tp==5)
            printf("%lld\n",query(1,1));
    }
    return 0;
}
